<?php
require 'bootstrap.php';
$newsItems = $db->query("SELECT title, topic, DATE_FORMAT(published_date, '%M %e, %Y') AS date, region, summary, content, COALESCE(image_url,'') AS image_url, tag FROM news WHERE news_status='published' ORDER BY published_date DESC, id DESC")->fetchAll();
$topicLabels = ['all'=>'All Topics'];
$regionLabels = ['all'=>'All Regions'];
foreach ($db->query("SELECT DISTINCT topic FROM news WHERE news_status='published' ORDER BY topic")->fetchAll(PDO::FETCH_COLUMN) as $topic) {
    $topicLabels[$topic] = ucwords(str_replace('_', ' ', $topic));
}
foreach ($db->query("SELECT DISTINCT region FROM news WHERE news_status='published' ORDER BY region")->fetchAll(PDO::FETCH_COLUMN) as $newsRegion) {
    $regionLabels[$newsRegion] = $newsRegion;
}
?>
